insert into recipes (kitchen_id, title, subtitle, category, difficulty, yield_text, prep_time_active, prep_time_passive, cost_total, cost_per_kg, sections, is_custom) values ('11111111-1111-4111-8111-111111111111', 'Beetroot Pesto', 'Rebové besto', 'Dressings & Cold Sauces', 'Easy', NULL, NULL, '45 min', NULL, NULL, '[{"type": "table", "rows": [["Beetroot", "100 g (roast 150°C, 45 min)"], ["Coriander", "10 g"], ["Rice vinegar", "to taste"], ["Parmesan, grated", "20 g"], ["Pine nuts", "20 g"], ["Salt", "to taste"], ["Garlic paste", "1/4 clove"]]}, {"type": "steps", "heading": "Method", "items": ["Roast the beetroot whole, wrapped in foil, at 150°C for about 45 minutes until a knife slides in easily. Cool and peel.", "Roughly chop the roasted beetroot and blend with coriander, a splash of rice vinegar, and the garlic paste.", "Pulse in the pine nuts and grated parmesan, keeping some texture rather than blending completely smooth.", "Season with salt to taste. Loosen with a little olive oil or water if too thick."]}]'::jsonb, false);
