-- ============================================================
-- 07_production_time.sql
-- ============================================================
-- Sautero — adds an editable "production time" to each recipe.
-- This is separate from the existing active/passive method-time estimates (which are
-- guessed from the written steps) — production time is something the chef sets directly,
-- and will later be used by the Mise en Place / prep-list feature to plan a station's day.
alter table recipes add column if not exists production_time text;

-- ============================================================
-- 08_ingredient_substitutes.sql
-- ============================================================
-- Sautero — adds origin, season, and substitution info to each ingredient.
alter table ingredients add column if not exists origin text;
alter table ingredients add column if not exists season text;
alter table ingredients add column if not exists substitutes text;

-- ============================================================
-- 09_tasks_schema.sql
-- ============================================================
-- Sautero — Mise en Place / prep task list
-- A task can optionally point at a recipe (to borrow its title/production time) or stand
-- entirely on its own. Priority 1 = critical, 5 = low. Kitchen-scoped (same pattern as
-- recipes/ingredients) so this is ready for a shared team board later without a schema
-- change — for now the app only shows "my" view of it, per Richard's 2026-07-09 call.
create table if not exists tasks (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid not null references kitchens(id),

  station text,
  task text not null,
  priority smallint not null default 3 check (priority between 1 and 5),

  recipe_id uuid references recipes(id) on delete set null,
  production_time text,

  done boolean not null default false,
  created_by uuid references auth.users(id),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table tasks enable row level security;

create policy "read kitchen tasks" on tasks
  for select using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );
create policy "write kitchen tasks" on tasks
  for insert with check (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );
create policy "update kitchen tasks" on tasks
  for update using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );
create policy "delete kitchen tasks" on tasks
  for delete using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );

-- ============================================================
-- 10_ingredient_substitutes_seed.sql
-- ============================================================
-- Sautero — fills origin/season/substitutes for the existing 535 ingredients.
-- Run AFTER 08_ingredient_substitutes.sql (which adds the columns) and after
-- 06_ingredients_seed.sql (which creates the rows this matches against by name).
-- Season is intentionally left blank for most meat/poultry/eggs/dry goods/spices/
-- sauces/dairy/alcohol/most seafood — treated as year-round in professional kitchen
-- sourcing; only genuinely seasonal produce/herbs/fruit/truffle/wild mushroom got a
-- season value. Substitutes are left blank for ~33 generic/placeholder or truly
-- irreplaceable items (water, plain salt, "protein of choice", etc.).

update ingredients set origin = 'Global — cane (tropical) & beet (temperate Europe)', season = NULL, substitutes = 'Honey or glucose syrup can replace in many recipes, though sweetness and moisture will differ.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Sugar');
update ingredients set origin = 'Global', season = NULL, substitutes = NULL where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Salt');
update ingredients set origin = 'Global', season = NULL, substitutes = NULL where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Water');
update ingredients set origin = 'Central Asia, cultivated worldwide', season = 'June–September (EU fresh harvest); cured bulbs available year-round', substitutes = 'Garlic powder (about 1/8 tsp per clove) or asafoetida for an allium-free option; shallot for a milder note.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Garlic');
update ingredients set origin = 'Global — dairy', season = NULL, substitutes = 'Margarine or a neutral oil for cooking; ghee for a higher smoke point and nuttier flavor.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Butter');
update ingredients set origin = 'Global — dairy', season = NULL, substitutes = 'Any unsweetened plant milk in a pinch; water-thinned cream approximates whole milk.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Milk');
update ingredients set origin = 'China / Japan', season = NULL, substitutes = 'Tamari for a gluten-free option; coconut aminos for a milder, slightly sweeter substitute.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Soy Sauce');
update ingredients set origin = 'Mediterranean', season = NULL, substitutes = 'Another mild vegetable oil for cooking; flavor won''t match for dressings or finishing.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Olive Oil');
update ingredients set origin = 'Global — dairy', season = NULL, substitutes = 'Whole milk whisked with melted butter (roughly 3:1); crème fraîche for a tangier result.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Cream');
update ingredients set origin = 'Global — poultry', season = NULL, substitutes = 'Aquafaba for vegan emulsification, though richness will differ.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Egg Yolk');
update ingredients set origin = 'East Asia', season = 'Year-round (greenhouse/import); best fresh spring–autumn', substitutes = 'Chives, or the green tops of leeks or regular onion.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Spring Onion');
update ingredients set origin = 'South & Southeast Asia', season = 'Year-round via import; fresh/young ginger peaks autumn in origin regions', substitutes = 'Galangal for a sharper, more citrusy note; ground dried ginger (about 1/4 the quantity) if fresh is unavailable.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Ginger');
update ingredients set origin = 'Global — poultry', season = NULL, substitutes = NULL where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Egg');
update ingredients set origin = 'East Asia', season = NULL, substitutes = 'White wine vinegar diluted slightly with water; apple cider vinegar with a pinch of sugar.' where kitchen_id = '11111111-1111-4111-8111-111111111111' and lower(name) = lower('Rice Vinegar');
