-- ============================================================
-- 11_task_status.sql
-- ============================================================
-- Sautero — replaces the simple done/not-done checkbox on tasks with a 3-state status:
-- TO DO -> CHECK -> FINISH. "CHECK" is for a task that's done but wants someone (e.g. the
-- chef) to verify it before it counts as truly finished.
alter table tasks add column if not exists status text not null default 'todo'
  check (status in ('todo','check','finish'));

update tasks set status = case when done then 'finish' else 'todo' end;

-- ============================================================
-- 12_order_list_schema.sql
-- ============================================================
-- Sautero — Order List: per-station checklist of ingredients to order, with quantity + unit.
-- A row existing here means "this ingredient is currently on this station's order list" —
-- unchecking an item in the app deletes its row rather than flagging it inactive.
create table if not exists order_list_items (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid not null references kitchens(id),
  station text not null,
  ingredient_id uuid not null references ingredients(id) on delete cascade,
  quantity numeric,
  unit text not null check (unit in ('kg','l','pc')),
  created_by uuid references auth.users(id),
  updated_at timestamptz not null default now(),
  unique (kitchen_id, station, ingredient_id)
);

alter table order_list_items enable row level security;

create policy "read kitchen order list" on order_list_items
  for select using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );
create policy "write kitchen order list" on order_list_items
  for insert with check (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );
create policy "update kitchen order list" on order_list_items
  for update using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );
create policy "delete kitchen order list" on order_list_items
  for delete using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );

-- ============================================================
-- 13_nutrition_schema.sql
-- ============================================================
-- Sautero — adds standard nutrition-label values (per 100g/100ml) to each ingredient.
-- The app computes a recipe's total nutrition from these the same way it already computes
-- recipe cost from ingredient prices — matching ingredient lines by name, converting units,
-- and summing.
alter table ingredients add column if not exists kcal_per_100g numeric;
alter table ingredients add column if not exists protein_g_per_100g numeric;
alter table ingredients add column if not exists carbs_g_per_100g numeric;
alter table ingredients add column if not exists fat_g_per_100g numeric;

