-- ============================================================
-- 29_translate_prep_sheets_en.sql
-- ============================================================
-- Sautero — translates all German prep-sheet data (dish + item names) to English, per
-- Richard's request. Name-based updates, so it doesn't matter which seed file a row came
-- from. One genuinely ambiguous word is handled first with a scoped update: 'Salat' means
-- 'Lettuce' on the Lobby burger/sandwich but 'Salad' on the Extra staff meal. Safe to
-- re-run (updates simply match nothing the second time).

-- Ambiguous case first: Extra station's 'Salat' is a side salad, not lettuce
update prep_items set name = 'Salad' where name = 'Salat' and dish_id in (select id from prep_dishes where station = 'Extra');
update prep_items set name = 'Lettuce' where name = 'Salat';

-- Dishes
update prep_dishes set name = 'Butterhead Salad' where name = 'Kopfsalat';
