-- ============================================================
-- 30_ingredients_storage_season.sql
-- ============================================================
-- Sautero — extends ingredients with two new filterable dimensions Richard asked for, scoped
-- down from the full "master ingredient database" spec to what's actually needed for the
-- Ingredients season/storage-type filter (not the full 20k-row/multi-table architecture —
-- that's a separate, paused decision). Adds columns only; the data fill (existing 535
-- ingredients + ~765 new ones to reach ~1300) comes from the background research pass and
-- lands in db/31_ingredients_expansion.sql.
alter table ingredients add column if not exists storage_type text
  check (storage_type in ('Dry Storage','Refrigerated','Freezer','Room Temperature'));
alter table ingredients add column if not exists seasons text[] not null default '{}';
  -- subset of {'Spring','Summer','Autumn','Winter'} — empty array means year-round/not seasonal

-- ============================================================
-- 31_ingredients_backfill_storage_season.sql
-- ============================================================
-- Sautero — backfills storage_type and seasons for all 533 existing ingredients (added by
-- 30_ingredients_storage_season.sql, currently NULL/empty on every row), and splits the
-- generic 'Produce' category into 'Fruit' / 'Vegetable' so the Ingredients screen can filter
-- on something more useful than one catch-all bucket.
--
-- Same honesty standard as 06_ingredients_seed.sql and 14_nutrition_seed.sql: every value here
-- is a reasoned estimate from general professional-kitchen storage practice and Central European
-- growing-season knowledge, not a lab/supplier-verified fact. storage_type reflects how the
-- ingredient is actually kept in a working hotel kitchen (e.g. onions/garlic/potatoes are kept at
-- Room Temperature, not refrigerated — refrigeration accelerates sprouting and off-flavours in
-- alliums and tubers). seasons is left as an empty array for anything that is genuinely
-- year-round or non-seasonal by nature (spices, dry goods, dairy, most meat, oils, sauces,
-- alcohol) — only ~120 of these 533 rows get a real season, deliberately mirroring the honest
-- ratio used when the old freeform `season` column was first filled in. Treat every value below
-- as a strong starting point to correct from real experience, not a confirmed fact.
--
-- This is scoped to the ~1300-ingredient demo/presentation database (533 existing + ~765 new in
-- 32_ingredients_expansion_new.sql), not the full 20,000-row master ingredient database concept
-- discussed elsewhere and separately paused — that spec does not apply here.
--
-- Run AFTER 30_ingredients_storage_season.sql. Matches all 533 rows by exact name + kitchen_id
-- (the same 535-ish reference set as 06_ingredients_seed.sql; the live count is 533 distinct
-- ingredient names). Safe to re-run — every statement is an idempotent UPDATE keyed on name.

