-- 36_prep_hidden.sql
-- ============================================================
-- Sautero — hide (not delete) a Check List item, dish, or whole section. Hidden rows stay in
-- the database (unlike delete) and can be brought back via a "Show hidden" toggle in the app.
alter table prep_dishes add column if not exists hidden boolean not null default false;
alter table prep_items add column if not exists hidden boolean not null default false;

-- ============================================================
-- 37_prep_soft_delete.sql
-- ============================================================
-- Sautero — "Delete" on a Check List item/dish/section now soft-deletes (recoverable) instead
-- of permanently removing the row, after Richard accidentally deleted/hid real data with no
-- way to undo it. Separate flag from `hidden` (36_prep_hidden.sql) — hidden = "skip today, on
-- purpose, always reversible"; deleted = "meant to remove this, but mistakes happen too."
alter table prep_dishes add column if not exists deleted boolean not null default false;
alter table prep_items add column if not exists deleted boolean not null default false;

-- ============================================================
-- 38_station_icons.sql
-- ============================================================
-- Sautero — custom icon per section, chosen when creating it (instead of always falling back
-- to the generic 📍 pin for anything not in the hardcoded STATION_ICONS map). Kitchen-wide
-- (not device-local like hidden-station-tiles/print-queue) since an icon is part of a
-- section's shared identity — everyone on the team should see the same one.
create table if not exists station_icons (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid not null references kitchens(id),
  station text not null,
  icon text not null,
  created_by uuid references auth.users(id),
  created_at timestamptz not null default now(),
  unique (kitchen_id, station)
);
alter table station_icons enable row level security;

create policy "read kitchen station icons" on station_icons
  for select using (kitchen_id in (select kitchen_id from profiles where id = auth.uid()));
create policy "write kitchen station icons" on station_icons
  for insert with check (kitchen_id in (select kitchen_id from profiles where id = auth.uid()));
create policy "update kitchen station icons" on station_icons
  for update using (kitchen_id in (select kitchen_id from profiles where id = auth.uid()));

-- ============================================================
-- 39_working_time.sql
-- ============================================================
-- Sautero — Working Time: real check-in/check-out time tracking. Overtime is a fixed 8h/day
-- threshold (Richard's own rule — "ak človek pracuje viac ako osem hodín v daný deň" — not
-- tied to the contracted weekly hours below).
--
-- "Next day off" and "contracted hours" live directly on profiles as simple, per-person,
-- manually-set fields rather than being derived from the existing Schedule roster: the
-- Schedule's `staff_members` rows (18_schedule_v2_schema.sql) are just names entered by a
-- manager, with no link to an actual login account, so there's no reliable way today to match
-- "the person currently logged in" to "a row in that roster." Simpler and correct now; wiring
-- staff_members to profiles.id is a separate future project if the roster needs to drive this.
create table if not exists time_entries (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid not null references kitchens(id),
  user_id uuid not null references auth.users(id),
  check_in timestamptz not null,
  check_out timestamptz,
  break_minutes int not null default 0,
  created_at timestamptz not null default now()
);
alter table time_entries enable row level security;

create policy "read own time entries" on time_entries
  for select using (user_id = auth.uid());
create policy "insert own time entries" on time_entries
  for insert with check (user_id = auth.uid() and kitchen_id in (select kitchen_id from profiles where id = auth.uid()));
create policy "update own time entries" on time_entries
  for update using (user_id = auth.uid());
create policy "delete own time entries" on time_entries
  for delete using (user_id = auth.uid());

alter table profiles add column if not exists contracted_hours_per_week numeric;
alter table profiles add column if not exists next_vacation_date date;
alter table profiles add column if not exists contract_notes text;

