-- ============================================================
-- 46_supplier_ingredients.sql
-- ============================================================
-- Sautero -- REAL supplier-priced ingredients from Swiss wholesaler price lists (DRAFT for review).
--
-- Source 1: Caviezel Giovanettoni AG, 2026 frozen/fresh food supplier price list (92-page PDF,
--   pre-extracted to text). All prices below are quoted "article no." references back to this
--   catalog (e.g. "article no. 41501") so Richard can look up and double-check any line item.
-- Source 2: Swiss Gastro Solutions "Sortiment" catalog (5-page PDF, ~19 products) was reviewed
--   in full but contributed NOTHING to this file -- every item in it (Mini-Schinkengipfeli,
--   Apero-Chuechli, Frueglingsrollen, Jalapenos mit Frischkaese, Schinkengipfel, Wienerli im
--   Teig, Strudel, etc.) is a branded, pre-formed finished snack/pastry product, not a base
--   ingredient a chef would write into a recipe's ingredient list. Excluded per scope.
--
-- Currency conversion: all source prices are CHF, explicitly excl. VAT. This app's ingredients
--   table stores everything as price_currency = 'EUR' (a pre-existing quirk of the 535-row seed
--   data, kept for consistency -- the UI hardcodes a EUR symbol regardless of the stored
--   currency, so switching to CHF here would look wrong against the rest of the price book).
--   Conversion used: 1 CHF ~= 1.06 EUR (rough/approximate, NOT a live FX rate -- just enough to
--   keep these real Swiss prices roughly comparable to the rest of the EUR-denominated book).
--   All converted prices are rounded to 2 decimals.
--
-- Scope: only genuine base ingredients were extracted -- the kind of thing a chef actually
--   writes as a line in a recipe's ingredient table (e.g. "Broccoli", "Cream", "Whole Milk",
--   "Salmon Fillet", "Eggs"). Branded/prepared/finished convenience products (McCain, JOWA, HUG,
--   Frigemo, Kern & Sammet, Bina ready-meals, breaded/formed/panierte items, pre-dressed salads,
--   Boiron fruit-puree line, ready-made sauces branded as "SGS", frozen pastries, ice cream,
--   coffee capsules, canned goods, non-food) were deliberately skipped even though the source
--   catalog runs to thousands of SKUs. Vegetable "Gemuesemischungen" (pre-made mixes) were
--   skipped in favor of their single-vegetable components.
--
-- Summary: 104 rows total, no duplicate names within this batch.
--   ~50 are brand-new ingredients not previously in the 535-row seed (or its 32_* expansion).
--   ~54 match an existing ingredient name exactly and will UPDATE that row's price/currency/
--   notes only (via ON CONFLICT DO UPDATE) -- upgrading it from an ESTIMATED price to this
--   REAL, sourced Swiss wholesale price. No other column (category, nutrition, origin, etc.)
--   is touched on conflict, so nothing else on an existing row gets clobbered.
--   By category: Fruit 18, Vegetable 39 (incl. mushrooms), Seafood 8, Dairy 20,
--   Dairy Alternatives 1, Eggs 4, Sauces & Condiments 4, Oils & Vinegars 1,
--   Chocolate & Cocoa 4, Dry Goods & Pantry 2, Grains & Flour 1, Bakery 2.
--
-- Two deliberate name-collision decisions worth flagging for review:
--   1. "Salmon Fillet" and "Prawn" already exist in 32_ingredients_expansion_new.sql (as
--      ESTIMATED prices) -- this file updates both to the real Caviezel price.
--   2. A few sourced items were intentionally named to AVOID colliding with an existing row
--      that uses a different unit (pc vs kg/l) for the same concept, since ON CONFLICT DO
--      UPDATE here only touches price/currency/notes and would silently mismatch a kg/L price
--      against a 'pc' unit otherwise. Examples: "Liquid Egg Yolk" / "Liquid Egg White" /
--      "Liquid Whole Egg" (new kg-priced liquid-egg SKUs, distinct from the existing per-piece
--      "Egg Yolk"/"Egg White"/"Whole Egg" rows) and "Shortcrust Pastry Dough" (new kg-priced raw
--      dough roll, distinct from the existing per-piece blind-baked "Shortcrust Pastry Shell").
--
-- Deliberately NOT included: Kiwi, Orange, Melon, and Pineapple pricing from the source catalog
--   were all sourced from a pre-cut/convenience-format SKU (e.g. "Kiwi geschnitten", fresh-cut
--   fruit salad line) whose price reflects prep labor, not raw fruit cost -- updating the
--   existing plain "Kiwi"/"Orange"/"Pineapple" estimates with those numbers would have been
--   misleading, so those four were dropped rather than force-fit.
--
-- Run after 06_ingredients_seed.sql and 32_ingredients_expansion_new.sql. Review before
-- applying to production -- this is a DRAFT and has not been run against the live database.

-- Fruit
insert into ingredients (kitchen_id, name, aliases, cuisine, category, unit, price, price_currency, notes) values ('11111111-1111-4111-8111-111111111111', 'Apple', ARRAY['Apfel']::text[], 'European', 'Fruit', 'kg', 4.35, 'EUR', 'Price from Caviezel Giovanettoni AG 2026 supplier price list (CHF 4.10/kg -> EUR conversion @1.06), article no. 41501.') on conflict (kitchen_id, lower(name)) do update set price = excluded.price, price_currency = excluded.price_currency, notes = excluded.notes;
insert into ingredients (kitchen_id, name, aliases, cuisine, category, unit, price, price_currency, notes) values ('11111111-1111-4111-8111-111111111111', 'Apricot', ARRAY['Aprikosen']::text[], 'European', 'Fruit', 'kg', 6.82, 'EUR', 'Price from Caviezel Giovanettoni AG 2026 supplier price list (CHF 6.43/kg -> EUR conversion @1.06), article no. 41817.') on conflict (kitchen_id, lower(name)) do update set price = excluded.price, price_currency = excluded.price_currency, notes = excluded.notes;
insert into ingredients (kitchen_id, name, aliases, cuisine, category, unit, price, price_currency, notes) values ('11111111-1111-4111-8111-111111111111', 'Blackberry', ARRAY['Brombeeren']::text[], 'European', 'Fruit', 'kg', 7.92, 'EUR', 'Price from Caviezel Giovanettoni AG 2026 supplier price list (CHF 7.47/kg -> EUR conversion @1.06), article no. 40210.') on conflict (kitchen_id, lower(name)) do update set price = excluded.price, price_currency = excluded.price_currency, notes = excluded.notes;
insert into ingredients (kitchen_id, name, aliases, cuisine, category, unit, price, price_currency, notes) values ('11111111-1111-4111-8111-111111111111', 'Blackcurrant', ARRAY['Cassis']::text[], 'European', 'Fruit', 'kg', 16.63, 'EUR', 'Price from Caviezel Giovanettoni AG 2026 supplier price list (CHF 15.69/kg -> EUR conversion @1.06), article no. 40250.') on conflict (kitchen_id, lower(name)) do update set price = excluded.price, price_currency = excluded.price_currency, notes = excluded.notes;
insert into ingredients (kitchen_id, name, aliases, cuisine, category, unit, price, price_currency, notes) values ('11111111-1111-4111-8111-111111111111', 'Cranberry', ARRAY['Cranberries']::text[], 'European', 'Fruit', 'kg', 20.03, 'EUR', 'Price from Caviezel Giovanettoni AG 2026 supplier price list (CHF 18.90/kg -> EUR conversion @1.06), article no. 41613.') on conflict (kitchen_id, lower(name)) do update set price = excluded.price, price_currency = excluded.price_currency, notes = excluded.notes;
insert into ingredients (kitchen_id, name, aliases, cuisine, category, unit, price, price_currency, notes) values ('11111111-1111-4111-8111-111111111111', 'Strawberry', ARRAY['Erdbeeren']::text[], 'European', 'Fruit', 'kg', 6.57, 'EUR', 'Price from Caviezel Giovanettoni AG 2026 supplier price list (CHF 6.20/kg -> EUR conversion @1.06), article no. 41330.') on conflict (kitchen_id, lower(name)) do update set price = excluded.price, price_currency = excluded.price_currency, notes = excluded.notes;
