-- ============================================================
-- 47_kitchen_currency.sql
-- ============================================================
-- Sautero — kitchen-wide display currency (Richard: "chcem mať možnosť v hlavnom menu zmeniť
-- menu eura frank dolár"). Every ingredient price is still stored in EUR (matches the existing
-- 535+ ingredient rows and every cost calculation in the app) — this column only controls how
-- prices are *displayed*, for the whole team at once, via a fixed approximate conversion rate
-- (see CURRENCY_INFO in app/index.html), not a live exchange rate. Changing it is gated to
-- admins in the app (a Home-screen tile), since it affects what every device shows, not just
-- the one making the change.
--
-- Defaulting to CHF, not EUR: Richard is running this kitchen in Switzerland, where Swiss
-- Francs are the real local currency, and the investor presentation is also being done in CHF.
-- Adding the column with `default 'CHF'` backfills every existing kitchen row (there's currently
-- only the one pilot kitchen) to CHF immediately, without needing to know/guess its id.
alter table kitchens add column if not exists display_currency text not null default 'CHF';

-- ============================================================
-- 48_kitchens_and_station_icons_policy_fix.sql
-- ============================================================
-- Sautero — two missing RLS policies found while auditing everything built this session against
-- the actual database policies (Richard asked "aký SQL ti chýba?" — good catch to check).
-- Both would fail SILENTLY under RLS (Postgres RLS defaults to deny, no error surfaced unless
-- the code checks for it) rather than loudly, so neither would have been obvious until someone
-- actually hit the button in production.
--
-- 1) kitchens has never had an UPDATE policy — it was only ever inserted at creation
--    (34_teams_access_gate.sql) and read for its name. The currency switcher
--    (47_kitchen_currency.sql) is the first feature that ever needs to update a kitchens row
--    itself (`kitchens.display_currency`), and without this, that update would silently no-op
--    for every admin who taps it.
create policy "admin update own kitchen" on kitchens
  for update using (
    exists (select 1 from profiles where id = auth.uid() and kitchen_id = kitchens.id and is_admin)
  );

-- 2) station_icons has select/insert/update policies but no DELETE policy. The section
--    rename feature (app/index.html: saveEditStation()) deletes the old station's icon row
--    before upserting the new one under the renamed station — without this, that delete would
--    silently fail, leaving a stale orphaned icon row behind under the old name.
create policy "delete kitchen station icons" on station_icons
  for delete using (kitchen_id in (select kitchen_id from profiles where id = auth.uid()));

-- ============================================================
-- 49_retire_schweizerhof_naming.sql
-- ============================================================
-- Sautero — retiring Hotel Schweizerhof branding from recipe/dish names (2026-07-13).
--
-- Richard: the pilot kitchen is changing to Burrito Bandito & Lido, and the concrete thing that
-- needs to go is anything literally named/branded after the old employer — not the general
-- Schedule/Check-List structure or the other ~172 recipes, which he confirmed he didn't source
-- from them ("nič iné som od nich nepoužil").
--
-- Searched every SQL file in this project for "Schweizerhof" in an actual recipe/dish title
-- (not just a comment) and found exactly three: one recipe, two Check List dishes. This
-- RENAMES them (drops the "Schweizerhof " prefix) rather than deleting them outright — the
-- underlying dish (a brioche, a coq au vin blanc, a chocolate mousse) is a standard classic,
-- not the hotel's proprietary content; it's the naming that ties it to them. If you'd rather
-- these were deleted outright instead of just renamed, say so and a delete version is a
-- two-line change.

update recipes set title = 'Brioche'
where title = 'Schweizerhof Brioche' and kitchen_id = '11111111-1111-4111-8111-111111111111';

update prep_dishes set name = 'Coq au Vin Blanc'
where name = 'Schweizerhof Coq au Vin Blanc' and kitchen_id = '11111111-1111-4111-8111-111111111111';

update prep_dishes set name = 'Chocolate Mousse'
where name = 'Schweizerhof Chocolate Mousse' and kitchen_id = '11111111-1111-4111-8111-111111111111';

-- Belt-and-suspenders: catches the row if migration 29's DE→EN translation never actually ran
-- against your live DB and it's still sitting in German.
update prep_dishes set name = 'Chocolate Mousse'
where name = 'Schweizerhof Schokoladenmousse' and kitchen_id = '11111111-1111-4111-8111-111111111111';

-- ============================================================
-- 50_enable_realtime.sql
-- ============================================================
-- Sautero — turn on Realtime for Check List's live cross-device sync (2026-07-13).
--
-- MVP_DEFINITION.md promises "updates visible to everyone in real time" for Check List — this
-- was never actually true until now; every screen only loaded data once per visit. The app
-- side (app/index.html: subscribeToRealtimeUpdates()) now subscribes to live change events on
-- these two tables, but Supabase only pushes events for tables explicitly added to the
-- `supabase_realtime` publication — this migration does that.
--
-- If you get an error like "relation is already member of publication" when running this,
-- that's fine — it just means Realtime was already on for that table. Nothing else to do.

alter publication supabase_realtime add table prep_items;
alter publication supabase_realtime add table prep_dishes;

-- ============================================================
-- 51_error_logs.sql
-- ============================================================
-- Sautero — basic client-side error tracking (2026-07-13).
-- Backlog v2 (QA Lead): "keď sa niečo pokazí u cudzieho človeka na jeho telefóne, nedozvieš sa
-- to, kým ti sám nenapíše." This is the minimal version — no third-party service (Sentry etc.),
-- just a table + a window.onerror handler that logs to it (app/index.html).
create table if not exists error_logs (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid references kitchens(id),
  user_id uuid references auth.users(id),
  message text not null,
  stack text,
  url text,
  user_agent text,
  created_at timestamptz not null default now()
);
alter table error_logs enable row level security;

-- Anyone signed in can log an error against their own kitchen — this has to stay permissive
-- (not scoped tighter) since the whole point is capturing errors even when other app state is
-- broken/inconsistent.
create policy "log own errors" on error_logs
  for insert with check (auth.uid() is not null);

-- Only admins can read the log — this is diagnostic data about staff devices, not something
-- every team member needs visibility into.
create policy "admin read error logs" on error_logs
  for select using (
    exists (select 1 from profiles where id = auth.uid() and is_admin)
  );

-- ============================================================
-- 52_usage_events.sql
-- ============================================================
-- Sautero — minimal usage analytics (2026-07-13).
-- Backlog v2 (PM + CTO): "bez telemetrie nevieš, či 25 ľudí appku reálne používa alebo len raz
-- otvorilo." No third-party analytics — a plain events table, logged from app/index.html at
-- login and whenever a top-level module (Recipes, Check List, Ingredients, ...) is opened.
create table if not exists usage_events (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid references kitchens(id),
  user_id uuid references auth.users(id),
  name text not null,
  meta jsonb,
  created_at timestamptz not null default now()
);
alter table usage_events enable row level security;

create policy "log own usage events" on usage_events
  for insert with check (auth.uid() is not null);

-- Only admins can read it back — this is usage/behavior data about the team, not something
-- every member needs to see about each other.
create policy "admin read usage events" on usage_events
  for select using (
    exists (select 1 from profiles where id = auth.uid() and is_admin)
  );

-- ============================================================
-- 53_invite_expiry_and_remove_member.sql
-- ============================================================
-- Sautero — expiring/revocable invite links + ability to remove a team member (2026-07-13).
-- Backlog v2 (CTO + Solution Architect): the invite link was literally the kitchen's own id —
-- never expires, can't be revoked without breaking the kitchen itself, and there was no way to
-- remove someone from a team at all once they joined.

-- A real, separate invite token (not the kitchen's own id) — revocable and expiring on its own,
-- with no effect on the kitchen itself either way.
create table if not exists kitchen_invites (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid not null references kitchens(id),
  created_by uuid references auth.users(id),
  created_at timestamptz not null default now(),
  expires_at timestamptz not null default (now() + interval '7 days'),
  revoked boolean not null default false
);
alter table kitchen_invites enable row level security;

-- Has to be readable by someone who isn't a team member yet (they're about to use the link to
-- decide whether to join) — same reasoning as the existing "read any kitchen name" policy on
-- kitchens itself.
create policy "read any invite" on kitchen_invites
  for select using (auth.uid() is not null);
create policy "create kitchen invite" on kitchen_invites
  for insert with check (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );
create policy "revoke own kitchen invite" on kitchen_invites
  for update using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );

-- Team members need to be able to see each other's names at all — profiles previously only
-- exposed your own row to yourself, so there was no way to render a member list in the first
-- place, separate from the ability to remove anyone.
create policy "read kitchen teammates" on profiles
  for select using (
    kitchen_id is not null and kitchen_id in (
      select kitchen_id from profiles p2 where p2.id = auth.uid()
    )
  );

-- Admin-only: remove a member from their own kitchen by clearing their kitchen_id — same state
-- as a brand-new signup, they can create or join a (possibly different) kitchen afterward.
create policy "admin remove kitchen member" on profiles
  for update using (
    kitchen_id is not null and kitchen_id in (
      select kitchen_id from profiles p2 where p2.id = auth.uid() and p2.is_admin
    )
  );

-- ============================================================
-- 54_check_list_audit_log.sql
-- ============================================================
-- Sautero — Check List audit log (2026-07-13).
-- Backlog v2 (Solution Architect + PM): the MVP promise is "everyone sees what's done
-- and what's not, without a single conversation about whose fault it is" — but until now
-- nothing recorded WHO changed an item, only its current state. This adds a lightweight
-- append-only trail: every status/on-hand/priority/notes change on a prep_item gets one row
-- here, visible to the whole kitchen (not admin-only — the point is shared visibility, same
-- as the checklist itself).
create table if not exists check_list_audit_log (
  id uuid primary key default gen_random_uuid(),
  kitchen_id uuid references kitchens(id),
  item_id uuid references prep_items(id) on delete cascade,
  item_name text not null,
  dish_name text,
  station text,
  field text not null,
  old_value text,
  new_value text,
  changed_by uuid references auth.users(id),
  changed_by_name text,
  created_at timestamptz not null default now()
);
create index if not exists check_list_audit_log_item_idx on check_list_audit_log(item_id, created_at desc);

alter table check_list_audit_log enable row level security;

create policy "kitchen members read audit log" on check_list_audit_log
  for select using (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );

create policy "kitchen members write audit log" on check_list_audit_log
  for insert with check (
    kitchen_id in (select kitchen_id from profiles where id = auth.uid())
  );

-- ============================================================
-- 55_fix_profiles_rls_recursion.sql
-- ============================================================
-- Sautero — URGENT fix for a live outage: infinite recursion in profiles RLS (2026-07-13).
--
-- db/53 added two policies ON `profiles` that query `profiles` again inside their own USING
-- clause (aliased p2) to find the caller's kitchen_id / admin status:
--   "read kitchen teammates" -> select kitchen_id from profiles p2 where p2.id = auth.uid()
--   "admin remove kitchen member" -> ...where p2.id = auth.uid() and p2.is_admin
--
-- To resolve that inner subquery, Postgres has to re-apply every SELECT policy on `profiles`
-- to the subquery itself — including "read kitchen teammates" again — which recurses with no
-- stopping point until Postgres raises 42P17 "infinite recursion detected in policy for
-- relation profiles". Confirmed live via a REST probe on 2026-07-13: this doesn't just break
-- direct profiles queries, it breaks EVERY table whose RLS subqueries profiles — recipes,
-- ingredients, prep_items, prep_dishes, access_requests, kitchen_invites insert/update,
-- error_logs, usage_events, check_list_audit_log. Effectively a full app outage since db/53
-- was run.
--
-- Fix: move the "what's my kitchen_id" / "am I admin" lookup into a SECURITY DEFINER function.
-- A SECURITY DEFINER function runs with its owner's privileges, so its internal `select` does
-- NOT re-trigger RLS on profiles — no self-reference, no recursion.

create or replace function my_kitchen_id()
returns uuid
language sql
security definer
stable
set search_path = public
as $$
  select kitchen_id from profiles where id = auth.uid()
$$;

create or replace function my_kitchen_id_if_admin()
returns uuid
language sql
security definer
stable
set search_path = public
as $$
  select kitchen_id from profiles where id = auth.uid() and is_admin
$$;

drop policy if exists "read kitchen teammates" on profiles;
create policy "read kitchen teammates" on profiles
  for select using (
    kitchen_id is not null and kitchen_id = my_kitchen_id()
  );

drop policy if exists "admin remove kitchen member" on profiles;
create policy "admin remove kitchen member" on profiles
  for update using (
    kitchen_id is not null and kitchen_id = my_kitchen_id_if_admin()
  );

-- ============================================================
-- 56_force_logout_all_devices.sql
-- ============================================================
-- Sautero — force every device to log out and require a fresh email code (run on demand).
--
-- This is not a schema change — it's a one-off action, safe to run again anytime the same
-- way. It deletes every active session (Supabase Auth cascades this to the matching refresh
-- tokens), so no device can silently refresh its way back in.
--
-- Caveat: a device's CURRENT access token stays valid until it naturally expires (project
-- default is 1 hour) even after this runs — deleting the session stops it from being
-- *renewed*, it doesn't retroactively invalidate a token that's still live. For an immediate
-- kick (not just "next refresh"), also do this in the dashboard: Authentication -> Users ->
-- select all -> "Sign out" (or lower the JWT expiry under Authentication -> Settings, run
-- this, then set it back).
--
-- This logs YOU out too, on every device — including the one you run this from once its
-- token expires. Have your email ready to grab the next code.

delete from auth.sessions;

